   'use client';

   import React, { useEffect, useState } from 'react';
   import { useOmegaChat } from '../hooks/useOmegaChat';
   import { useVoiceEngine } from '../hooks/useVoiceEngine';
   import { useIsMobile } from '../hooks/useIsMobile';
   import { OmegaHeader } from '../components/omega/OmegaHeader';
   import { ChatView } from '../components/omega/ChatView';
   import { ChatComposer } from '../components/omega/ChatComposer';
   import { ConversationSidebar } from '../components/omega/ConversationSidebar';
   import { TelemetryPanel } from '../components/omega/TelemetryPanel';
   import { VoiceMode } from '../components/omega/VoiceMode';
   import { SettingsModal } from '../components/omega/SettingsModal';
   import { SystemStateDrawer } from '../components/omega/SystemStateDrawer';

   export default function Index() {
     const chat = useOmegaChat();
     const voice = useVoiceEngine();
     const isMobile = useIsMobile();

     // Modal state management
     const [settingsOpen, setSettingsOpen] = useState(false);
     const [stateDrawerOpen, setStateDrawerOpen] = useState(false);
     const [sidebarOpen, setSidebarOpen] = useState(!isMobile);
     const [telemetryOpen, setTelemetryOpen] = useState(!isMobile);

     // Voice mode tracking
     const voiceModeActive = voice.isListening || voice.voiceState !== 'idle';

     // Auto-send transcript when voice listening completes
     useEffect(() => {
       if (
         voice.transcript &&
         voice.voiceState === 'idle' &&
         !voice.isListening
       ) {
         const finalText = voice.transcript.trim();
         if (finalText) {
           chat.sendMessage(finalText);
           voice.exitVoiceMode();
         }
       }
     }, [voice.voiceState, voice.isListening, voice.transcript]);

     // Event handlers for all interactions
     const handleVoiceStart = () => voice.startListening();
     const handleVoiceStop = () => voice.stopListening();
     const handleVoiceInterrupt = () => voice.interruptSpeech();
     const handleSendMessage = (text: string) => chat.sendMessage(text);
     const handleNewConversation = async () => await chat.createConversation();
     const handleSelectConversation = async (id: string) => await chat.switchConversation(id);
     const handleDeleteConversation = async (id: string) => {
       if (confirm('Delete this conversation?')) {
         await chat.deleteConversation(id);
       }
     };
     const handleSettingsChange = (settings: any) => {
       voice.updateSettings(settings);
       setSettingsOpen(false);
     };

     // Responsive sidebar behavior
     useEffect(() => {
       setSidebarOpen(!isMobile);
       setTelemetryOpen(!isMobile);
     }, [isMobile]);

     return (
       <div className='flex h-screen bg-white'>
         {/* 3-Column Layout */}
         <ConversationSidebar
           conversations={chat.conversations}
           activeConvoId={chat.activeConvoId}
           onSelectConversation={handleSelectConversation}
           onNewConversation={handleNewConversation}
           onDeleteConversation={handleDeleteConversation}
           isOpen={sidebarOpen}
         />

         {/* Main Content: Header + ChatView + ChatComposer */}
         <div className='flex flex-col flex-1'>
           <OmegaHeader
             title='OmegA'
             subtitle='Powered by Vercel & Neon'
             onMenuClick={() => setSidebarOpen(!sidebarOpen)}
             onSettingsClick={() => setSettingsOpen(true)}
           />
           <ChatView
             messages={chat.messages}
             isStreaming={chat.streaming}
             systemState={chat.systemState}
             error={chat.error}
           />
           <ChatComposer
             onSendMessage={handleSendMessage}
             onVoiceStart={handleVoiceStart}
             isStreaming={chat.streaming}
             isVoiceActive={voiceModeActive}
             heardText={voice.interimTranscript || voice.transcript}
           />
         </div>

         {/* Right Telemetry Panel */}
         <TelemetryPanel
           systemState={chat.systemState}
           streaming={chat.streaming}
           messagesCount={chat.messages.length}
           sessionId={chat.activeConvoId || undefined}
           isOpen={telemetryOpen}
         />

         {/* All Modals and Overlays */}
         <VoiceMode
           isActive={voiceModeActive}
           state={voice.voiceState}
           transcript={voice.transcript}
           interimTranscript={voice.interimTranscript}
           onStop={handleVoiceStop}
           onInterrupt={handleVoiceInterrupt}
         />
         <SettingsModal
           isOpen={settingsOpen}
           onClose={() => setSettingsOpen(false)}
           settings={voice.settings}
           onSettingsChange={handleSettingsChange}
         />
         <SystemStateDrawer
           isOpen={stateDrawerOpen}
           onClose={() => setStateDrawerOpen(false)}
           state={{
             chatState: chat.systemState,
             voiceState: voice.voiceState,
             activeSession: chat.activeConvoId,
             messageCount: chat.messages.length,
             streaming: chat.streaming,
           }}
         />

         {/* Mobile-only telemetry toggle */}
         {isMobile && (
           <button
             onClick={() => setStateDrawerOpen(!stateDrawerOpen)}
             className='fixed bottom-4 right-4 z-40 p-3 bg-gray-900 text-white rounded-full shadow-lg'
             title='Toggle system state'
           >
             ⚙️
           </button>
         )}
       </div>
     );
   }
   ```

